import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  public void testSerializeNulls() throws Exception {
    GsonBuilder builder = new GsonBuilder();
    // Initially serializeNulls should be default (likely false)
    Field serializeNullsField = GsonBuilder.class.getDeclaredField("serializeNulls");
    serializeNullsField.setAccessible(true);
    boolean initialValue = serializeNullsField.getBoolean(builder);
    assertFalse(initialValue);

    // Call serializeNulls method
    GsonBuilder returnedBuilder = builder.serializeNulls();

    // Assert method returns same instance for chaining
    assertSame(builder, returnedBuilder);

    // Assert serializeNulls field is now true
    boolean updatedValue = serializeNullsField.getBoolean(builder);
    assertTrue(updatedValue);
  }
}
